		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;8&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;: 8&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;- 8&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&amp;nbsp;&lt;/span&gt;&lt;/span&gt;= 512&amp;nbsp;: 512&amp;nbsp;- 64&amp;nbsp;= 448&amp;nbsp;&amp;rarr; 512&amp;nbsp;: 448&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;So the middle number should be 7.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;7&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;: 7&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;- 7&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;= 343&amp;nbsp;: 343&amp;nbsp;- 49&amp;nbsp;= 294&amp;nbsp;&amp;rarr; 343&amp;nbsp;: 294&lt;span style=&quot;font-weight: 700; &quot;&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
